module RefModule(
    input clk,
    input reset,
    input start,
    input receive,
    input forward,
    output reg [1:0] current_state
);
    // State encoding
    parameter IDLE = 2'b00, LISTENING = 2'b01, LEARNING = 2'b10, FORWARDING = 2'b11;
    reg [1:0] unused_next_state;

    // State transition logic
    always @(*) begin
        case (current_state)
            IDLE: begin
                if (start) unused_next_state = LISTENING;
                else unused_next_state = IDLE;
            end
            LISTENING: begin
                if (receive) unused_next_state = LEARNING;
                else unused_next_state = LISTENING;
            end
            LEARNING: begin
                if (forward) unused_next_state = FORWARDING;
                else unused_next_state = LEARNING;
            end
            FORWARDING: begin
                unused_next_state = IDLE; // transition back to IDLE for demo purposes
            end
            default: unused_next_state = IDLE;
        endcase
    end

    // State update logic
    always @(posedge clk or posedge reset) begin
        if (reset)
            current_state <= IDLE;
        else
            current_state <= unused_next_state;
    end
endmodule
